const widgetUUID = "123e4567-e89b-12d3-a456-426614174002";
const apiURL = "https://viaframe.iys.org.tr";
const targetSection = document.getElementById(widgetUUID);
if (targetSection) { /* loading ui */ }

fetch(apiURL + "/widget/publicKey/" + widgetUUID, { method: "GET" })
  .then(r => r.text())
  .then(t => JSON.parse(t))
  .then(data => {
    const parts = data.message[0].split("|");
    if (document.location.hostname === parts[1]) {
      return fetch(apiURL + "/widget/load-widget/" + widgetUUID + "?apinoncekey=" + parts[0]);
    }
    throw new Error("Invalid domain");
  })
  .then(r => r.json())
  .then(data => {
    if (data.js) { const s=document.createElement("script"); s.textContent=data.js; document.body.appendChild(s); }
    if (data.css){ const st=document.createElement("style"); st.textContent=data.css; document.head.appendChild(st); }
  });

